module.exports=class{constructor(...e){if(0===e.length)this.side_a=null,this.side_b=null,this.hypotenuse=null;else if(2===e.length)this.side_a=e[0],this.side_b=e[1],this.hypotenuse=null;else{if(3!==e.length)throw new Error("wrong number of arguments");this.side_a=e[0],this.side_b=e[1],this.hypotenuse=e[2]}}Author(){console.log("pseudo: Tina-1300\ngithub: https://github.com/Tina-1300 created on 03/11/2024")}IsRectangle(e=this.hypotenuse,t=this.side_a,s=this.side_b){if(null===e||null===t||null===s)throw new Error("Invalid parameters: 'hypotenuse', 'side_a' and 'side_b' must be defined and not null.");return Math.pow(e,2)==Math.pow(t,2)+Math.pow(s,2)}AdjacentSide(e=this.hypotenuse,t=this.side_b){if(null===t||null===e)throw new Error("Invalid parameters: 'hypotenuse' and 'side_b' must be defined and not null.");return Math.sqrt(Math.pow(e,2)-Math.pow(t,2))}Hypotenus(e=this.side_a,t=this.side_b){if(null===e||null===t)throw new Error("Invalid parameters: 'side_a' and 'side_b' must be defined and not null.");return Math.sqrt(Math.pow(e,2)+Math.pow(t,2))}};